1	export type Cell = [number, number];
2	
3	const coordKey = (x: number, y: number): string => `${x},${y}`;
4	
5	const NEIGHBOR_OFFSETS: ReadonlyArray<readonly [number, number]> = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [ 0, -1],          [ 0, 1],
8	  [ 1, -1], [ 1, 0], [ 1, 1],
9	];
10	
11	export function nextGeneration(cells: Cell[]): Cell[] {
12	  const liveKeys = new Set(cells.map(([x, y]) => coordKey(x, y)));
13	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
14	
15	  for (const [x, y] of cells) {
16	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
17	      const nx = x + dx;
18	      const ny = y + dy;
19	      const k = coordKey(nx, ny);
20	      const existing = neighborCounts.get(k);
21	      if (existing) existing.count += 1;
22	      else neighborCounts.set(k, { cell: [nx, ny], count: 1 });
23	    }
24	  }
25	
26	  const survives = (key: string, count: number): boolean =>
27	    liveKeys.has(key) ? count === 2 || count === 3 : count === 3;
28	
29	  const result: Cell[] = [];
30	  for (const [k, { cell, count }] of neighborCounts) {
31	    if (survives(k, count)) result.push(cell);
32	  }
33	  return result;
34	}
