1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	const sortCells = (cells: Cell[]): Cell[] =>
5	  [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
6	
7	describe("Game of Life - nextGeneration", () => {
8	  it("should return empty array for empty input", () => {
9	    expect(nextGeneration([])).toEqual([]);
10	  });
11	  it("should kill a lone live cell", () => {
12	    expect(nextGeneration([[0, 0]])).toEqual([]);
13	  });
14	  it("Rule 1 Underpopulation: two adjacent cells each with 1 neighbor die", () => {
15	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
16	  });
17	  it("Rule 4 Reproduction: L-tromino produces a 2x2 block", () => {
18	    const gen0: Cell[] = [[0, 2], [1, 2], [0, 1]];
19	    const expected: Cell[] = [[0, 1], [0, 2], [1, 1], [1, 2]];
20	    expect(sortCells(nextGeneration(gen0))).toEqual(sortCells(expected));
21	  });
22	  it("Rule 2 Survival: live cell with 2 neighbors survives — middle of a horizontal triple", () => {
23	    // Horizontal row [(0,0),(1,0),(2,0)]. The middle (1,0) has 2 live neighbors and must survive.
24	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
25	    expect(result).toContainEqual([1, 0]);
26	  });
27	  it("Rule 3 Overpopulation: live cell with 4 neighbors dies — center of plus-shape", () => {
28	    // Center (1,1) is live with neighbors at (0,1),(2,1),(1,0),(1,2) — 4 neighbors → dies.
29	    const result = nextGeneration([[1, 1], [0, 1], [2, 1], [1, 0], [1, 2]]);
30	    expect(result).not.toContainEqual([1, 1]);
31	  });
32	  it("Block still life: 2x2 block remains unchanged", () => {
33	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
34	    expect(sortCells(nextGeneration(block))).toEqual(sortCells(block));
35	  });
36	  it.todo("Blinker oscillator: vertical [(0,0),(0,1),(0,2)] becomes horizontal [(-1,1),(0,1),(1,1)]");
37	  it.todo("should handle negative coordinates — blinker shifted to negative space oscillates correctly");
38	});
